app.get('/rest/products/search', async (req, res) => {
    const q = req.query.q || '';
    const query = `SELECT * FROM Products WHERE ((name LIKE '%${q}%' OR description LIKE '%${q}%') AND deletedAt IS NULL) ORDER BY name`;
    const [results] = await sequelize.query(query);
    res.json({ status: 'success', data: results });
